const ThemeContext = createContext('light'); // default: 'light'

// Case 1: no Provider in tree — default applies
function StandaloneButton() {
  const theme = useContext(ThemeContext);
  console.log(theme); // 'light' — the default
  return <button className={theme}>Click</button>;
}

// Case 2: inside a Provider — default does NOT apply
function App() {
  return (
    <ThemeContext.Provider value="dark">
      <StandaloneButton /> {/* logs 'dark', not 'light' */}
    </ThemeContext.Provider>
  );
}

const AuthContext = createContext(null); // null = 'no Provider'

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  return <AuthContext.Provider value={{ user, setUser }}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (ctx === null) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return ctx;
}

// Result:
// Inside AuthProvider → works correctly
// Outside AuthProvider → throws clear error: 'useAuth must be used within AuthProvider'

const ThemeContext = createContext({
  theme: 'light',
  setTheme: () => {}, // no-op setter — does nothing outside Provider
});

// Component works stand-alone (e.g. in Storybook):
function ThemeToggle() {
  const { theme, setTheme } = useContext(ThemeContext);
  return (
    <button onClick={() => setTheme(t => t === 'light' ? 'dark' : 'light')}>
      {theme}
    </button>
  );
}

// Renders in Storybook without any Provider — shows 'light'

const NO_PROVIDER = Symbol('UserContext: no provider');
const UserContext = createContext(NO_PROVIDER);

export function useUser() {
  const ctx = useContext(UserContext);
  if (ctx === NO_PROVIDER) {
    throw new Error('useUser: UserProvider is missing from the tree');
  }
  return ctx;
}

const ThemeContext = createContext('light');

// ✗ Missing value prop — consumers receive undefined, NOT 'light'
function App() {
  return (
    <ThemeContext.Provider>  {/* no value prop → value is undefined */}
      <Button />
    </ThemeContext.Provider>
  );
}

function Button() {
  const theme = useContext(ThemeContext);
  console.log(theme); // undefined — NOT 'light'
}

// ✓ Correct: always supply the value prop
<ThemeContext.Provider value="light">

// Default value (createContext argument) — fallback for consumers outside any Provider:
const ThemeContext = createContext('light'); // ← this is the DEFAULT

// Provider initial state (useState argument) — independent of the default:
function ThemeProvider({ children }) {
  const [theme, setTheme] = useState('dark'); // ← this is the INITIAL STATE
  return <ThemeContext.Provider value={theme}>{children}</ThemeContext.Provider>;
}

// Consumer inside ThemeProvider → receives 'dark' (provider's current state)
// Consumer outside ThemeProvider → receives 'light' (createContext default)

// With usable default, no Provider wrapper needed for simple tests:
const ThemeContext = createContext({ theme: 'light', setTheme: () => {} });

function Button() {
  const { theme } = useContext(ThemeContext);
  return <button className={theme}>OK</button>;
}

// Test — no Provider needed:
import { render, screen } from '@testing-library/react';
test('renders with default theme', () => {
  render(<Button />);
  expect(screen.getByRole('button')).toHaveClass('light');
});

// Test — override with a specific Provider:
test('renders with dark theme', () => {
  render(
    <ThemeContext.Provider value={{ theme: 'dark', setTheme: () => {} }}>
      <Button />
    </ThemeContext.Provider>
  );
  expect(screen.getByRole('button')).toHaveClass('dark');
});

