// Test specific context values without mounting the full Provider:
import { ThemeContext } from './ThemeContext';
import { render, screen } from '@testing-library/react';
import { Button } from './Button';

function renderWithTheme(ui, theme = 'light') {
  return render(
    <ThemeContext.Provider value={{ theme, setTheme: vi.fn() }}>
      {ui}
    </ThemeContext.Provider>
  );
}

test('applies dark class in dark mode', () => {
  renderWithTheme(<Button />, 'dark');
  expect(screen.getByRole('button')).toHaveClass('btn-dark');
});

test('applies light class in light mode', () => {
  renderWithTheme(<Button />, 'light');
  expect(screen.getByRole('button')).toHaveClass('btn-light');
});

const LevelContext = createContext(0); // default: 0

// Section reads current level and provides level + 1 to its children
function Section({ children }) {
  const level = useContext(LevelContext);
  return (
    <LevelContext.Provider value={level + 1}>
      {children}
    </LevelContext.Provider>
  );
}

function Heading() {
  const level = useContext(LevelContext);
  const Tag = `h${Math.min(level, 6)}`;
  return <Tag>Heading at level {level}</Tag>;
}

// Usage:
// <Heading /> outside any Section → level 0 (createContext default)
// <Section><Heading /></Section> → level 1 (Provider value)
// <Section><Section><Heading /></Section></Section> → level 2

// Development guard in the custom hook:
export function useTheme() {
  const ctx = useContext(ThemeContext);

  // Catch both null (no Provider) and undefined (Provider with no value prop)
  if (ctx == null) {
    if (process.env.NODE_ENV !== 'production') {
      throw new Error(
        'useTheme: ThemeProvider not found or provided undefined value.\n' +
        'Wrap your app with <ThemeProvider>.'
      );
    }
  }

  return ctx;
}

// ✗ This is evaluated once at module load, not per render:
const DynamicDefault = createContext(computeSomeValue());
// computeSomeValue() is called at import time, once, for the module lifetime.

// ✓ For truly dynamic fallback logic, use a hook wrapper:
export function useDynamicContext() {
  const ctx = useContext(MyContext);
  if (!ctx) {
    // Compute and return a local default:
    return { theme: detectSystemTheme(), setTheme: () => {} };
  }
  return ctx;
}

// A locale context for a component library:
const LocaleContext = createContext({
  locale: typeof navigator !== 'undefined' ? navigator.language : 'en',
  formatDate: (date) => date.toLocaleDateString(),
  formatNumber: (n) => n.toLocaleString(),
});

// Consumers of the library get sensible defaults for the user's browser locale.
// App authors can override by wrapping with <LocaleContext.Provider value={...}>.

class ContextErrorBoundary extends React.Component {
  state = { hasError: false, error: null };
  static getDerivedStateFromError(e) { return { hasError: true, error: e }; }
  render() {
    if (this.state.hasError) return <p>Config error: {this.state.error?.message}</p>;
    return this.props.children;
  }
}

// Usage:
<ContextErrorBoundary>
  <FeaturePanel /> {/* useTheme() throws if ThemeProvider is missing */}
</ContextErrorBoundary>
